        updatedAt: Value(model.updatedAt ?? DateTime.now()),
        syncStatus: Value(model.syncStatus ?? SyncStatus.synced));
    await insertOrUpdate(companion);
    return model;
  }

  /// Delete company by ID
  @override
  Future<int> deleteById(String id) =>
      (delete(companyTable)..where((t) => t.id.equals(id))).go();

  /// Watch all companys as a stream
  Stream<List<Company>> watchAll({QueryParams? queryParams}) {
    queryParams ??= QueryParams.empty;
    final query = select(companyTable);
    applyQueryParams(query, queryParams);
    return query.watch();
  }

  /// Watch company by ID as a stream
  Stream<Company?> watchById(String id, {QueryParams? queryParams}) {
    queryParams ??= QueryParams.empty;
    final query = select(companyTable)..where((t) => t.id.equals(id));
    applyQueryParams(query, queryParams);
    return query.watchSingleOrNull();
  }

  /// The primary table this DAO operates on.
  @override
  TableInfo<CompanyTable, Company> get table => companyTable;

  /// Get column expression for a field name
  @override
  Expression<Object>? getColumnForField(String fieldName) {
    switch (fieldName) {
      case 'id':
        return companyTable.id;
      case 'name':
        return companyTable.name;
      case 'departmentId':
        return companyTable.departmentId;
      case 'lastSyncedAt':
        return companyTable.lastSyncedAt;
      case 'createdAt':
        return companyTable.createdAt;
      case 'updatedAt':
        return companyTable.updatedAt;
      case 'syncStatus':
        return companyTable.syncStatus;
      default:
        return null;
    }
  }

  /// Get the data type for a field name
  @override
  String? getFieldType(String fieldName) {
    switch (fieldName) {
      case 'id':
        return 'String';
      case 'name':
        return 'String';
      case 'departmentId':
        return 'String';
      case 'lastSyncedAt':
        return 'DateTime';
      case 'createdAt':
        return 'DateTime';
      case 'updatedAt':
        return 'DateTime';
      case 'syncStatus':
        return 'SyncStatus';
      default:
        return null;
    }
  }

  /// Create ordering term for sorting
  @override
  OrderingTerm createOrderingTerm(SortCondition sort, CompanyTable table) {
    final column = getColumnForField(sort.field.fieldName);
    if (column == null) {
      throw ArgumentError('Unknown field for sorting: ${sort.field.fieldName}');
    }

    return OrderingTerm(
      expression: column,
      mode: sort.direction == SortDirection.ascending
          ? OrderingMode.asc
          : OrderingMode.desc,
    );
  }

  // Implementation of BaseDaoMixin methods
  @override
  Future<Company?> getByIdTyped(String id, {QueryParams? queryParams}) async {
    return await getById(id, queryParams: queryParams);
  }

  @override
  Future<List<Company>> getAllTyped({QueryParams? queryParams}) async {
    return await getAll(queryParams: queryParams);
  }

  @override
  Stream<Company?> watchByIdTyped(String id, {QueryParams? queryParams}) {
    return watchById(id, queryParams: queryParams);
  }

  @override
  Stream<List<Company>> watchAllTyped({QueryParams? queryParams}) {
    return watchAll(queryParams: queryParams);
  }

  /// Returns all companys whose IDs are not in [excludedIds].
  @override
  Future<List<Company>> getAllExcludingIds(
    Set<String> excludedIds, {
    QueryParams? queryParams,
  }) async {
    queryParams ??= QueryParams.empty;
    final query = select(companyTable)
      ..where((t) => t.id.isNotIn(excludedIds.toList()));
    applyQueryParams(query, queryParams);
    return query.get();
  }

  /// Delete all companys from the table
  @override
  Future<int> deleteAll() => delete(companyTable).go();
}
